query:
SHOW COLUMNS FROM tracked_bets LIKE '%Game%';
SELECT id, awayTeam, homeTeam, gameDate, anGameId, gameNumber, result, odds
FROM tracked_bets
WHERE gameDate = '2026-04-30' AND awayTeam = 'HOU' AND homeTeam = 'BAL'
ORDER BY anGameId ASC;

